window.__EMBEDDED_MODULES__['01-carbon-atom'] = {"id": "01-carbon-atom", "title": "The Carbon Atom's Journey", "description": "Follow a single carbon atom through Earth's interconnected cycle — from air to life to rock and back again.", "estimated_minutes": 5, "difficulty": "beginner", "prerequisites": [], "next_module": "02-keeling-curve", "stages": [{"id": "hook", "type": "text", "title": "A Carbon Atom's Journey", "body": "This carbon atom has been on Earth for <strong>4.5 billion years</strong>. It was forged in a dying star. It cycled through ancient seas, was buried and became limestone, rode a tectonic plate into a volcano, and erupted into the sky as CO₂.<br><br>About 200 years ago, humans started digging up carbon that had been buried for millions of years and burning it. <strong>Every second, we release ~634 tons of CO₂</strong> that nature took eons to store.<br><br>Where will <em>this</em> atom go next?", "callouts": [{"label": "Atmosphere CO₂ (April 2026)", "value": "431.12 ppm — highest in 3 million years"}, {"label": "Human emissions", "value": "~10.4 GtC/year released"}, {"label": "Natural sinks absorb", "value": "~5.9 GtC/year (57%)"}], "actions": [{"id": "begin", "label": "Begin the Journey →", "type": "next", "style": "primary"}]}, {"id": "explore_paths", "type": "branch", "title": "Choose Your Path", "description": "A carbon atom in the atmosphere can take many paths. Each one leads to a different fate — and a different timescale. Where does yours go?", "paths": [{"label": "🌿 Absorbed by a tree", "description": "Photosynthesis pulls CO₂ from the air. The atom becomes part of a glucose molecule in a leaf in Brazil.", "icon": "🌿"}, {"label": "🌊 Dissolved in the ocean", "description": "CO₂ dissolves into surface water, forming carbonic acid. The atom joins the ocean's vast carbon reservoir.", "icon": "🌊"}, {"label": "🔥 Burned in a fire", "description": "A wildfire releases the atom back into the atmosphere. In California's 2020 fires, this happened to billions of tons.", "icon": "🔥"}, {"label": "🪨 Buried as limestone", "description": "The atom is locked into calcium carbonate shells of marine organisms. Over millions of years, these become limestone rock.", "icon": "🪨"}, {"label": "⛽ Extracted and burned", "description": "Humans extract ancient fossil carbon and burn it for energy. The atom joins the ~37.8 Gt CO₂ we emit each year.", "icon": "⛽"}]}, {"id": "timescale_reveal", "type": "discover", "title": "The Deep Time Reveal", "body": "Each path operates on a completely different timescale:<br><br>🔥 <strong>Burning in fire:</strong> minutes<br>🌿 <strong>Tree absorption:</strong> seconds to years<br>🌊 <strong>Ocean mixing:</strong> centuries to millennia<br>🪨 <strong>Fossilization:</strong> millions of years<br><br>The problem? Humans are releasing carbon that took <strong>300 million years</strong> to bury — in just decades. We're moving carbon <strong>10 million times faster</strong> than nature ever did.<br><br><em>\"Carbon is patient. We are not.\"</em>", "callouts": [{"label": "Fast carbon cycle", "value": "Atmosphere ↔ Biosphere: days to decades"}, {"label": "Slow carbon cycle", "value": "Weathering & sedimentation: 100K+ years"}, {"label": "Fossil fuels", "value": "300 million years of stored sunlight"}], "gaia": "The carbon cycle is Earth's heartbeat. Right now, we're making it skip. The question isn't whether the cycle will continue — it's whether we'll still recognize the planet when it does.", "actions": [{"id": "quiz", "label": "Test Your Knowledge →", "type": "next", "style": "primary"}]}, {"id": "quiz", "type": "quiz", "title": "Test Your Knowledge", "questions": [{"question": "How many GtC do humans emit per year?", "options": ["~2 GtC", "~5 GtC", "~10 GtC", "~20 GtC"], "correct": 2, "explanation": "In 2023, fossil fuel emissions were ~10.4 GtC (37.8 Gt CO₂). The other options are too low or too high."}, {"question": "Which process removes CO₂ from the atmosphere?", "options": ["Burning fossil fuels", "Deforestation", "Photosynthesis", "Volcanic eruptions"], "correct": 2, "explanation": "Photosynthesis absorbs CO₂ and converts it to glucose + oxygen."}, {"question": "How long does it take nature to bury carbon as fossil fuels?", "options": ["100 years", "10,000 years", "1 million years", "~300 million years"], "correct": 3, "explanation": "Fossil fuels formed over 300+ million years. Humans release them in decades."}], "completionText": "You now understand that carbon atoms cycle through Earth's systems on timescales from seconds to millions of years — and that humans are disrupting this cycle at unprecedented speed."}, {"id": "connect", "type": "text", "title": "You Just Completed Module 1!", "body": "You've traced the journey of a single carbon atom through Earth's systems. You now understand that carbon cycles through Earth's systems on timescales from seconds to millions of years — and that humans are disrupting this cycle at unprecedented speed.<br><br><strong>Your score: check the XP above ↑</strong><br><br>Now let's see the evidence of this disruption in the atmosphere itself.", "callouts": [{"label": "Keeling Curve", "value": "The definitive record of atmospheric CO₂ — 1958 to today"}, {"label": "Next Module", "value": "The Keeling Curve Explorer"}], "actions": [{"id": "next_module", "label": "Explore the Keeling Curve →", "type": "next", "style": "primary"}]}]};

window.__EMBEDDED_MODULES__['02-keeling-curve'] = {"id": "02-keeling-curve", "title": "The Keeling Curve", "description": "Explore the iconic CO₂ measurement record from Mauna Loa — the most important dataset in climate science.", "estimated_minutes": 6, "difficulty": "beginner", "prerequisites": ["01-carbon-atom"], "next_module": "03-carbon-budget", "stages": [{"id": "hook", "type": "text", "title": "The Most Important Curve in Climate Science", "body": "In 1958, a young geochemist named <strong>Charles David Keeling</strong> began measuring CO₂ at the Mauna Loa Observatory in Hawaii, 3,400m above the Pacific Ocean.<br><br>His first reading: <strong>315.97 ppm</strong>.<br>Today's reading: <strong>~431 ppm</strong>.<br><br>That single dataset — the <strong>Keeling Curve</strong> — became the definitive proof that human activity is changing Earth's atmosphere. Every upward wobble tells a story of seasons, volcanoes, and our relentless burning of fossil fuels.", "callouts": [{"label": "Keeling's first reading (1958)", "value": "315.97 ppm"}, {"label": "Today (2026)", "value": "~431 ppm"}, {"label": "Increase since 1958", "value": "+115 ppm (+36%)"}], "gaia": "This is the most important graph in human history. Not because it's complex — because it's simple. One line. One direction. Up.", "actions": [{"id": "explore", "label": "Explore the Data →", "type": "next", "style": "primary"}]}, {"id": "timeline", "type": "timeline", "title": "Scrub Through Time", "description": "Drag the slider to see atmospheric CO₂ at key moments in history. Watch the curve accelerate.", "data": [{"label": "1958", "value": 315.97, "display": "315.97 ppm", "context": "Keeling begins measurements. Post-war boom begins."}, {"label": "1965", "value": 320.04, "display": "320.04 ppm", "context": "+4 ppm in 7 years. The curve begins its climb."}, {"label": "1975", "value": 330.75, "display": "330.75 ppm", "context": "Oil crisis. Even energy shocks don't slow the rise."}, {"label": "1988", "value": 351.48, "display": "351.48 ppm", "context": "Hansen testifies to Congress. Climate change enters public discourse."}, {"label": "1997", "value": 363.52, "display": "363.52 ppm", "context": "Kyoto Protocol signed. CO₂ doesn't sign treaties."}, {"label": "2005", "value": 379.76, "display": "379.76 ppm", "context": "An Inconvenient Truth. Awareness rises faster than CO₂. Almost."}, {"label": "2013", "value": 396.48, "display": "396.48 ppm", "context": "400 ppm imminent. A psychological threshold."}, {"label": "2016", "value": 404.24, "display": "404.24 ppm", "context": "Paris Agreement. The world agrees to act. CO₂ hits 400+."}, {"label": "2020", "value": 414.24, "display": "414.24 ppm", "context": "Pandemic lockdowns. Emissions dip 5%. Curve doesn't bend."}, {"label": "2023", "value": 421.08, "display": "421.08 ppm", "context": "Hottest year on record. The curve accelerates."}, {"label": "2026", "value": 431.12, "display": "431.12 ppm", "context": "Now. +115 ppm since Keeling began. 36% increase."}], "gaia": "Notice the spacing between the dots. They're getting closer together — not because time is speeding up, but because the rate of increase is accelerating. Each decade adds more CO₂ than the last.", "actions": [{"id": "continue", "label": "What does this mean? →", "type": "next", "style": "primary"}]}, {"id": "patterns", "type": "discover", "title": "What the Curve Tells Us", "body": "The Keeling Curve has three stories embedded in its shape:<br><br><strong>1. The Annual Sawtooth</strong> — CO₂ drops each spring (Northern Hemisphere plants absorb it) and rises each winter. This seasonal cycle has amplitude of ~6 ppm and is growing larger as vegetation patterns shift.<br><br><strong>2. The Steady Rise</strong> — The underlying trend is relentlessly upward. From 1958 to 2026: <strong>+115 ppm</strong>, an increase of 36%. Rate of increase: ~2.5 ppm/year (and accelerating).<br><br><strong>3. No Plateaus</strong> — Despite every climate agreement, every renewable energy milestone, every pledge — the curve has never bent downward. Not once. Not for a single year.<br><br>The pre-industrial CO₂ level was <strong>~280 ppm</strong>. We've added 151 ppm — roughly <strong>54% more CO₂</strong> than existed naturally.", "callouts": [{"label": "Pre-industrial CO₂", "value": "~280 ppm (800,000 year average)"}, {"label": "Today", "value": "431 ppm"}, {"label": "Rate of change", "value": "~2.5 ppm/year (20x faster than any natural change)"}], "gaia": "The curve doesn't care about our intentions. It only measures our actions. And so far, our actions say one thing: more.", "actions": [{"id": "quiz", "label": "Test Yourself →", "type": "next", "style": "primary"}]}, {"id": "quiz", "type": "quiz", "title": "Did You Read the Curve?", "questions": [{"question": "When did Charles Keeling begin his CO₂ measurements?", "options": ["1948", "1958", "1968", "1978"], "correct": 1, "explanation": "Keeling began continuous CO₂ measurements at Mauna Loa in March 1958."}, {"question": "What causes the annual sawtooth pattern in the Keeling Curve?", "options": ["Ocean currents", "Seasonal plant growth/decay cycles", "Volcanic activity", "Solar cycles"], "correct": 1, "explanation": "Plants absorb CO₂ during spring/summer growing seasons (Northern Hemisphere dominates due to more landmass), reducing atmospheric CO₂. In winter, decomposition and reduced photosynthesis cause CO₂ to rise."}, {"question": "What was the pre-industrial atmospheric CO₂ concentration?", "options": ["240 ppm", "280 ppm", "320 ppm", "350 ppm"], "correct": 1, "explanation": "Ice core records show CO₂ was ~280 ppm for the past 10,000 years before industrialization."}, {"question": "By how much has CO₂ increased since 1958?", "inputType": "number", "correct": 115, "tolerance": 5, "unit": "ppm", "hint": "First reading: 316 ppm. Today: ~431 ppm. What's the difference?"}], "completionText": "You can now read the most important graph in climate science. The evidence is clear: CO₂ is rising faster than ever recorded, and it's driven by human activity."}, {"id": "connect", "type": "text", "title": "You Now Understand the Keeling Curve!", "body": "You've traced the most important measurement in climate science. The evidence is clear: <strong>CO₂ is rising faster than ever recorded</strong>, and it's driven by human activity.<br><br>But there's a budget for this — a limit on how much more we can emit before we cross dangerous thresholds. That's the <strong>Carbon Budget</strong>.", "callouts": [{"label": "CO₂ increase since 1958", "value": "+115 ppm in 68 years"}, {"label": "Remaining carbon budget (1.5°C)", "value": "~200 GtCO₂ (at 2023 rates, ~5 years)"}], "actions": [{"id": "next_module", "label": "Explore the Carbon Budget →", "type": "next", "style": "primary"}]}]};

window.__EMBEDDED_MODULES__['03-carbon-budget'] = {"id": "03-carbon-budget", "title": "The Carbon Budget Game", "description": "Earth has a limited carbon budget to stay below 1.5°C. Spend wisely — or watch it run out.", "estimated_minutes": 7, "difficulty": "intermediate", "prerequisites": ["01-carbon-atom", "02-keeling-curve"], "next_module": "04-restoration-projects", "stages": [{"id": "hook", "type": "text", "title": "You Have a Budget. It's Running Out.", "body": "Imagine Earth's atmosphere like a bathtub. The drain (natural carbon sinks — oceans, forests) removes ~5.9 GtC/year. But we're pouring in <strong>10.4 GtC/year</strong> from fossil fuels and land use.<br><br>The <strong>carbon budget</strong> is how much more CO₂ we can emit while keeping warming below 1.5°C. According to the IPCC AR6:<br><br>🔴 <strong>Remaining budget from 2023: ~200 GtCO₂</strong><br><br>At current rates, we'll exhaust this in roughly <strong>5 years</strong>. After that, we are almost certainly locked into warming above 1.5°C.", "callouts": [{"label": "Total carbon budget (1.5°C)", "value": "500 GtCO₂ from 2020"}, {"label": "Already emitted", "value": "~300 GtCO₂ (60% used)"}, {"label": "Remaining budget", "value": "~200 GtCO₂"}, {"label": "Current annual emissions", "value": "~40 GtCO₂/year"}], "gaia": "We're spending a 500-year budget in 200 years. And we're accelerating. The bathtub is overflowing — and we're still turning up the tap.", "actions": [{"id": "play", "label": "Play the Budget Game →", "type": "next", "style": "primary"}]}, {"id": "slider_budget", "type": "slider", "title": "Allocate the Carbon Budget", "description": "You control how the remaining 200 GtCO₂ budget is spent across sectors. Every choice has consequences. Adjust each slider — but remember, the total can't exceed 200 GtCO₂ if we want to stay under 1.5°C.", "sliders": [{"label": "Fossil Fuel Emissions", "min": 0, "max": 100, "step": 5, "default": 45, "unit": "GtCO₂"}, {"label": "Deforestation & Land Use", "min": 0, "max": 50, "step": 5, "default": 12, "unit": "GtCO₂"}, {"label": "Industrial Processes", "min": 0, "max": 30, "step": 2, "default": 8, "unit": "GtCO₂"}, {"label": "Agriculture (CH₄ + N₂O)", "min": 0, "max": 35, "step": 5, "default": 15, "unit": "GtCO₂-eq"}], "gaia": "Here's the uncomfortable truth: even if you set every slider to zero except the minimum, you'd still struggle to stay within budget. That's not a design flaw — that's the math.", "actions": [{"id": "check", "label": "See if we're on track →", "type": "next", "style": "primary"}]}, {"id": "gauge_result", "type": "gauge", "title": "How Does Your Budget Look?", "description": "The gauge shows your total allocation against the 200 GtCO₂ limit.", "min": 0, "max": 250, "unit": "GtCO₂", "value": 80, "thresholds": [[50, "#5bbf72"], [80, "#ffa726"], [100, "#c45c4a"], [250, "#e53935"]], "gaugeContext": "The green zone means we're within budget. Yellow means we're cutting it close. Red means we've blown past 1.5°C. Most allocations end up in the red — because the budget is that tight.", "actions": [{"id": "quiz", "label": "Test Your Understanding →", "type": "next", "style": "primary"}]}, {"id": "quiz", "type": "quiz", "title": "Budget Check", "questions": [{"question": "What is the remaining carbon budget for 1.5°C (from 2023)?", "options": ["~100 GtCO₂", "~200 GtCO₂", "~500 GtCO₂", "~1000 GtCO₂"], "correct": 1, "explanation": "The IPCC AR6 assessed ~200 GtCO₂ remaining for a 50% chance of limiting warming to 1.5°C."}, {"question": "At 2023 emission rates, how many years until the 1.5°C budget is exhausted?", "options": ["~2 years", "~5 years", "~10 years", "~20 years"], "correct": 1, "explanation": "200 GtCO₂ ÷ ~40 GtCO₂/year ≈ 5 years."}, {"question": "Which sector contributes the most to annual emissions?", "options": ["Agriculture", "Deforestation", "Fossil fuel combustion", "Industrial processes"], "correct": 2, "explanation": "Fossil fuel combustion accounts for ~37 of the ~40 GtCO₂/year total."}], "completionText": "You now understand the brutal math: we're spending carbon 3-4x faster than we should be. The remaining budget is tiny, and every fraction of a degree matters."}, {"id": "connect", "type": "text", "title": "Budget Understood. Now Let's Fix It.", "body": "You now understand the brutal math: <strong>we're spending carbon 3-4x faster than we should be</strong>. The remaining budget is tiny, and every fraction of a degree matters.<br><br>But here's the hope — <strong>nature-based solutions and restoration projects</strong> are already removing carbon from the atmosphere at scale. Let's see what's happening on the ground.", "callouts": [{"label": "Carbon removal needed by 2050", "value": "~5-16 GtCO₂/year"}, {"label": "Nature-based solutions potential", "value": "~11 GtCO₂/year"}], "actions": [{"id": "next_module", "label": "Explore Restoration Projects →", "type": "next", "style": "primary"}]}]};

window.__EMBEDDED_MODULES__['04-restoration-projects'] = {"id": "04-restoration-projects", "title": "Restoration Projects Explorer", "description": "Discover nature-based carbon removal projects worldwide — from mangrove restoration in Indonesia to reforestation in the Amazon.", "estimated_minutes": 7, "difficulty": "intermediate", "prerequisites": ["01-carbon-atom", "02-keeling-curve", "03-carbon-budget"], "next_module": "05-carbon-market", "stages": [{"id": "hook", "type": "text", "title": "8,877 Projects Fighting for Our Planet", "body": "Across the globe, <strong>8,877 verified carbon projects</strong> are actively removing or avoiding CO₂ emissions. From protecting mangroves in Indonesia to building clean cookstoves in Kenya, these projects represent humanity's effort to repair what we've broken.<br><br>Each project is verified by standards like <strong>Verra (VCS)</strong> or the <strong>Gold Standard</strong>, ensuring real, measurable impact. Together, they represent <strong>billions of tons</strong> of CO₂ kept out of — or removed from — the atmosphere.", "callouts": [{"label": "Total verified projects", "value": "8,877 (Verra + Gold Standard)"}, {"label": "Total carbon credits issued", "value": "~4.2 billion credits to date"}, {"label": "Project types", "value": "Renewable energy, forestry, agriculture, methane capture"}], "gaia": "These aren't hypothetical solutions. They're real projects, on the ground, right now. The question isn't whether they work — it's whether we can scale them fast enough.", "actions": [{"id": "explore", "label": "Explore Projects →", "type": "next", "style": "primary"}]}, {"id": "cardstack", "type": "cardstack", "title": "Project Spotlight", "description": "Browse verified carbon removal projects. Click each card to learn more.", "filters": ["All", "Reforestation", "Renewable Energy", "Methane Capture", "Mangrove Restoration"], "cards": [{"title": "Tambopata-Bahuaja REDD+", "subtitle": "Peru · Amazon Rainforest", "icon": "🌴", "badge": "Verra VCS", "category": "Reforestation", "detail": "Protecting 591,119 hectares of tropical rainforest in the Peruvian Amazon. Avoids 4,571,426 tCO₂e over 10 years by preventing deforestation. Home to jaguars, macaws, and indigenous communities.", "stats": ["591K ha protected", "4.6M tCO₂e avoided", "10 years crediting"]}, {"title": "Kenya Cookstove Distribution", "subtitle": "Kenya · Rural Communities", "icon": "🍳", "badge": "Gold Standard", "category": "Methane Capture", "detail": "Distributing efficient cookstoves to 14,000+ households. Reduces firewood use by 50%, cutting CO₂ and improving indoor air quality. Women and children benefit most.", "stats": ["14,000+ stoves", "126,000 tCO₂e/yr", "50% fuel reduction"]}, {"title": "Indonesia Mangrove Restoration", "subtitle": "Kalimantan · Coastal Ecosystems", "icon": "🪸", "badge": "Verra VCS", "category": "Mangrove Restoration", "detail": "Restoring 10,000 hectares of degraded mangrove forests. Mangroves sequester 3-5x more carbon per hectare than terrestrial forests. Also protects coastal communities from storms.", "stats": ["10,000 ha restored", "50,000 tCO₂e/yr", "3-5x carbon density"]}, {"title": "India Wind Power Project", "subtitle": "Tamil Nadu · Clean Energy", "icon": "💨", "badge": "Gold Standard", "category": "Renewable Energy", "detail": "42 wind turbines generating 80 MW, displacing coal-fired electricity. Provides clean energy to 250,000 homes. Creates local jobs and energy independence.", "stats": ["80 MW capacity", "150,000 tCO₂e/yr", "250K homes powered"]}, {"title": "Congo Basin Peatlands", "subtitle": "DRC · Tropical Wetlands", "icon": "🌾", "badge": "Verra VCS", "category": "Reforestation", "detail": "Protecting 290,000 hectares of peatland forest — the world's largest tropical peatland complex, storing 30 billion tons of carbon. If drained, it would release centuries of stored carbon.", "stats": ["290K ha protected", "30B tons stored", "Critical carbon sink"]}, {"title": "Chile Solar Energy Initiative", "subtitle": "Atacama · Solar Power", "icon": "☀️", "badge": "Gold Standard", "category": "Renewable Energy", "detail": "Large-scale solar farm in the Atacama Desert generating 200 MW, replacing diesel generation in remote communities. The Atacama has the highest solar irradiance on Earth.", "stats": ["200 MW capacity", "330,000 tCO₂e/yr", "Atacama region"]}], "gaia": "Each of these projects is a story of people choosing to act. Not because it's easy — because the alternative is unthinkable.", "actions": [{"id": "continue", "label": "The Global Pattern →", "type": "next", "style": "primary"}]}, {"id": "global_pattern", "type": "discover", "title": "The Global Pattern", "body": "Zooming out, the distribution of projects reveals a stark pattern:<br><br>🌍 <strong>Tropical developing nations</strong> host most nature-based projects because they hold the planet's most carbon-rich ecosystems. But they've contributed least to the problem.<br><br>📊 <strong>The inequity:</strong> The top 10 historical emitters produced <strong>70%</strong> of all industrial CO₂. Yet climate impacts fall hardest on nations least equipped to adapt.<br><br>This is why <strong>climate justice</strong> is central to every carbon market negotiation. Finance must flow from high-emitting to vulnerable nations.", "callouts": [{"label": "Projects in developing countries", "value": "~78%"}, {"label": "Top 10 emitters share of historical CO₂", "value": "~70%"}, {"label": "Climate finance gap", "value": "$100B pledged, ~$83B delivered (2022)"}], "gaia": "The map of carbon projects is also a map of inequality. The places that did the least to cause this crisis are doing the most to fix it — and getting the least funding.", "actions": [{"id": "quiz", "label": "Test Your Knowledge →", "type": "next", "style": "primary"}]}, {"id": "quiz", "type": "quiz", "title": "Projects Smackdown", "questions": [{"question": "How many verified carbon projects exist globally?", "options": ["~2,000", "~5,000", "~8,877", "~15,000"], "correct": 2, "explanation": "As of 2026, there are 8,877 Verra and Gold Standard verified projects."}, {"question": "Which ecosystem sequesters 3-5x more carbon per hectare than forests?", "options": ["Grasslands", "Peatlands", "Mangroves", "Coral reefs"], "correct": 2, "explanation": "Mangrove forests store 3-5x more carbon per unit area than terrestrial forests due to dense root systems and waterlogged soils."}, {"question": "What fraction of carbon projects are in developing countries?", "options": ["~30%", "~50%", "~78%", "~95%"], "correct": 2, "explanation": "Approximately 78% of nature-based carbon projects are located in developing countries."}], "completionText": "You've seen that 8,877 real projects are fighting climate change on the ground. But how do they get funded? How are carbon credits priced, traded, and ensured to be real?"}, {"id": "connect", "type": "text", "title": "Projects Inspire. Markets Fund.", "body": "You've seen that <strong>8,877 real projects</strong> are fighting climate change on the ground. But how do they get funded? How are carbon credits priced, traded, and ensured to be real?<br><br>The <strong>carbon market</strong> is the financial system designed to do exactly that — but it's full of controversy and contradictions.", "callouts": [{"label": "Global voluntary carbon market (2025)", "value": "$2.2 billion"}, {"label": "Compliance market value", "value": "$909+ billion"}], "actions": [{"id": "next_module", "label": "Enter the Carbon Market →", "type": "next", "style": "primary"}]}]};

window.__EMBEDDED_MODULES__['05-carbon-market'] = {"id": "05-carbon-market", "title": "The Carbon Market Explorer", "description": "How is carbon priced, traded, and sold? Explore the voluntary and compliance markets — and the controversies that surround them.", "estimated_minutes": 8, "difficulty": "intermediate", "prerequisites": ["03-carbon-budget", "04-restoration-projects"], "next_module": "06-drawdown-solutions", "stages": [{"id": "hook", "type": "text", "title": "Can You Put a Price on the Planet?", "body": "Carbon markets are supposed to be simple: <strong>make polluters pay, fund those who remove carbon.</strong> In practice, they're one of the most complex and controversial tools in the climate fight.<br><br>Two markets exist:<br>1. <strong>Compliance markets</strong> (like the EU ETS) — legally mandated, covering ~23% of global emissions<br>2. <strong>Voluntary markets</strong> — companies buy credits to offset their footprint<br><br>In 2025, the <strong>voluntary market was worth $2.2 billion</strong> and the <strong>EU ETS alone hit $909 billion</strong>.<br><br>But 30-40% of voluntary credits may not represent real reductions. The system is broken — but is the concept itself flawed?", "callouts": [{"label": "EU ETS market value (2025)", "value": "$909 billion"}, {"label": "Voluntary market value (2025)", "value": "$2.2 billion"}, {"label": "Estimated junk credits", "value": "30-40% of voluntary market"}], "gaia": "Putting a price on carbon is either the most elegant solution to climate change — or the most dangerous form of greenwashing. The truth depends on whether the price is real.", "actions": [{"id": "compare", "label": "Compare the Markets →", "type": "next", "style": "primary"}]}, {"id": "comparison", "type": "comparison", "title": "Markets Compared", "description": "How do the two major carbon market types actually differ?", "col1Header": "Compliance", "col2Header": "Voluntary", "comparisonData": [{"category": "Governance", "col1": "Government-regulated (EU, California, RGGI)", "col2": "Self-regulated by registries (Verra, Gold Standard)"}, {"category": "Participants", "col1": "Mandatory for covered industries", "col2": "Companies, individuals (anyone can buy)"}, {"category": "Price range", "col1": "$50-100+/ton (EU ETS reached €100 in 2023)", "col2": "$3-50/ton (highly variable)"}, {"category": "Verification", "col1": "Rigorous government monitoring", "col2": "Third-party audits (quality varies)"}, {"category": "Market size", "col1": "$909B (2025)", "col2": "$2.2B (2025)"}, {"category": "Integrity concerns", "col1": "Political lobbying, allowance oversupply", "col2": "Additionality questions, overcrediting"}], "gaia": "The compliance market is 400x larger than the voluntary market. If you want to change the climate, follow the big money — it's in compliance.", "actions": [{"id": "timeline", "label": "Price History →", "type": "next", "style": "primary"}]}, {"id": "price_timeline", "type": "timeline", "title": "EU Carbon Price History", "description": "Trace the EU ETS price from launch to today — it tells the story of climate policy ambition.", "data": [{"label": "2005", "value": 8.05, "display": "€8.05", "context": "EU ETS launches. Free allowances flood the market."}, {"label": "2008", "value": 22.5, "display": "€22.50", "context": "Peak before the financial crisis crash."}, {"label": "2012", "value": 6.5, "display": "€6.50", "context": "Oversupply crash. Price collapses. Carbon is nearly free."}, {"label": "2018", "value": 16.0, "display": "€16.00", "context": "Market Stability Reserve introduced. Price begins recovery."}, {"label": "2021", "value": 55.0, "display": "€55.00", "context": "Fit for 55 package. EU commits to 55% emissions cut by 2030."}, {"label": "2023", "value": 100.0, "display": "€100.00", "context": "Historic milestone: carbon hits €100/ton."}, {"label": "2026", "value": 72.0, "display": "€72.00", "context": "Current price. Still below the $100+ needed for 1.5°C."}], "gaia": "The price of carbon is the price of our future. At €72/ton, we're still underpaying. The IPCC estimates we need $100-150/ton by 2030 to stay on track.", "actions": [{"id": "quiz", "label": "Test Yourself →", "type": "next", "style": "primary"}]}, {"id": "quiz", "type": "quiz", "title": "Carbon Market Literacy", "questions": [{"question": "What was the EU ETS carbon price at its 2023 peak?", "options": ["€50", "€75", "€100", "€150"], "correct": 2, "explanation": "The EU ETS price hit €100 in February 2023, a historic milestone."}, {"question": "Which is larger: the compliance or voluntary carbon market?", "options": ["Voluntary", "They're equal", "Compliance", "Neither exists"], "correct": 2, "explanation": "The compliance market ($909B) is ~400x larger than the voluntary market ($2.2B)."}, {"question": "What percentage of voluntary credits may not represent real reductions?", "options": ["5-10%", "15-20%", "30-40%", "60-70%"], "correct": 2, "explanation": "Studies suggest 30-40% of voluntary carbon credits don't deliver promised reductions."}, {"question": "What carbon price does the IPCC estimate is needed by 2030 for 1.5°C?", "inputType": "number", "correct": 100, "tolerance": 50, "unit": "$/ton", "hint": "It's between $50 and $200 per ton. The higher end is more likely."}], "completionText": "Carbon markets are powerful but imperfect. The price signal matters — $100/ton changes behavior. But markets alone won't solve this crisis."}, {"id": "connect", "type": "text", "title": "Markets Are Tools — Not Solutions", "body": "Carbon markets are powerful but imperfect. The price signal matters — <strong>$100/ton changes behavior</strong>. But markets alone won't solve this crisis.<br><br>Real solutions require <strong>systemic transformation</strong>: switching energy systems, protecting forests, redesigning cities, and rethinking how we produce and consume.<br><br>Let's explore what those solutions actually look like.", "callouts": [{"label": "Needed carbon price for 1.5°C", "value": "$50-100+/ton by 2030"}, {"label": "Top drawdown solutions potential", "value": "~1,000 GtCO₂ by 2050"}], "actions": [{"id": "next_module", "label": "Discover Drawdown Solutions →", "type": "next", "style": "primary"}]}]};

window.__EMBEDDED_MODULES__['06-drawdown-solutions'] = {"id": "06-drawdown-solutions", "title": "Drawdown Solutions Explorer", "description": "The 100 most substantive solutions to reverse global warming — ranked, compared, and scored by impact.", "estimated_minutes": 8, "difficulty": "intermediate", "prerequisites": ["03-carbon-budget", "05-carbon-market"], "next_module": "07-carbon-footprint", "stages": [{"id": "hook", "type": "text", "title": "100 Solutions That Can Reverse Global Warming", "body": "Drawdown is the point at which greenhouse gases in the atmosphere stop climbing and start to decline. According to <strong>Project Drawdown</strong>, there are <strong>100+ viable solutions</strong> across every sector that could achieve this.<br><br>These aren't pie-in-the-sky ideas — they're <strong>existing technologies and practices</strong> that are already being deployed. The question isn't whether solutions exist. It's whether we can deploy them <strong>fast enough and at scale</strong>.<br><br>The top 5 solutions by potential impact:<br>1. 🌾 Reduced food waste — <strong>87.45 GtCO₂-eq</strong><br>2. 💨 Onshore wind turbines — <strong>147.7 GtCO₂</strong><br>3. 🌊 Offshore wind turbines — <strong>139.7 GtCO₂</strong><br>4. 🧊 Improved refrigeration — <strong>89.74 GtCO₂</strong><br>5. 🌱 Tropical forest restoration — <strong>83.56 GtCO₂</strong>", "callouts": [{"label": "Total solutions identified", "value": "82 substantive solutions"}, {"label": "Combined potential impact", "value": "1,500+ GtCO₂-eq by 2050"}, {"label": "Net cost (many save money)", "value": "Trillions in savings over time"}], "gaia": "The solutions exist. Every single one. The gap isn't technology — it's will. Let's see what's possible.", "actions": [{"id": "explore", "label": "Explore Solutions →", "type": "next", "style": "primary"}]}, {"id": "cardstack", "type": "cardstack", "title": "Solution Spotlight", "description": "Explore the top drawdown solutions. Filter by sector.", "filters": ["All", "Energy", "Food & Agriculture", "Land Use", "Buildings & Cities", "Transport"], "cards": [{"title": "Onshore Wind Turbines", "subtitle": "Energy Sector · #1 Ranked", "icon": "💨", "badge": "#1 Solution", "category": "Energy", "detail": "Wind turbines on land. Reduces CO₂ by avoiding fossil fuel electricity generation. Cost: $36/ton CO₂ avoided. Creates local jobs and energy independence. Now cheaper than coal in most markets.", "stats": ["147.7 GtCO₂ potential", "30% cheaper since 2010", "Generates in 100+ countries"]}, {"title": "Reduced Food Waste", "subtitle": "Food & Agriculture · #2 Ranked", "icon": "🌾", "badge": "#2 Solution", "category": "Food & Agriculture", "detail": "One-third of all food produced is lost or wasted. Reducing this by 50% by 2050 could avoid 87.45 GtCO₂-equivalent. Requires cold chains, better storage, and consumer education.", "stats": ["87.45 GtCO₂-eq avoided", "1/3 of food wasted globally", "$4.4T in food value lost"]}, {"title": "Plant-Rich Diets", "subtitle": "Food & Agriculture · #3 Ranked", "icon": "🥦", "badge": "#3 Solution", "category": "Food & Agriculture", "detail": "Shifting toward plant-based diets reduces methane from livestock and land-use change. Without giving up meat entirely, even moderate shifts have massive impact.", "stats": ["66.11 GtCO₂-eq avoided", "14.5% of global emissions from livestock", "Land freed for reforestation"]}, {"title": "Tropical Forest Restoration", "subtitle": "Land Use · #5 Ranked", "icon": "🌴", "badge": "#5 Solution", "category": "Land Use", "detail": "Restoring degraded tropical forests to capture carbon, protect biodiversity, and regulate water cycles. Two billion hectares of land are suitable for restoration worldwide.", "stats": ["83.56 GtCO₂ potential", "2B hectares restorable", "Critical biodiversity habitat"]}, {"title": "Rooftop Solar", "subtitle": "Buildings & Cities · #10 Ranked", "icon": "☀️", "badge": "#10 Solution", "category": "Buildings & Cities", "detail": "Distributed solar panels on rooftops. Reduces transmission losses, democratizes energy, and lowers electricity costs for households. Cost dropped 90% since 2010.", "stats": ["36.59 GtCO₂ potential", "Cost dropped 90% since 2010", "400+ GW installed worldwide"]}, {"title": "Electric Vehicles", "subtitle": "Transport · #26 Ranked", "icon": "🚗", "badge": "#26 Solution", "category": "Transport", "detail": "Replacing internal combustion engines with electric vehicles powered by clean electricity. Battery costs fell 97% since 1991. EVs are now cost-competitive with gas cars.", "stats": ["28.47 GtCO₂ potential", "Battery costs $139/kWh (2025)", "40M EVs sold in 2024"]}], "gaia": "Notice something? None of these solutions require technology that doesn't exist yet. Every one is available today. The barrier isn't invention — it's deployment.", "actions": [{"id": "continue", "label": "What If We Deploy Faster? →", "type": "next", "style": "primary"}]}, {"id": "slider_impact", "type": "slider", "title": "What If We Deployed Solutions Faster?", "description": "Adjust deployment speed to see the impact on atmospheric CO₂ by 2050. How much difference does speed make?", "sliders": [{"label": "Renewable Energy Adoption", "min": 0, "max": 100, "step": 10, "default": 50, "unit": "% scale"}, {"label": "Reforestation Rate", "min": 0, "max": 100, "step": 10, "default": 30, "unit": "% scale"}, {"label": "Food Waste Reduction", "min": 0, "max": 100, "step": 10, "default": 40, "unit": "% scale"}, {"label": "Building Efficiency", "min": 0, "max": 100, "step": 10, "default": 25, "unit": "% scale"}], "gaia": "At 100% deployment across all solutions, we could avoid over 1,500 GtCO₂ by 2050. That's enough to reverse the curve. But at current rates, we're deploying at about 20-30% of what's needed.", "actions": [{"id": "quiz", "label": "Test Yourself →", "type": "next", "style": "primary"}]}, {"id": "quiz", "type": "quiz", "title": "Solutions Smackdown", "questions": [{"question": "What is the #1 ranked drawdown solution?", "options": ["Solar farms", "Onshore wind turbines", "Nuclear power", "Electric vehicles"], "correct": 1, "explanation": "Onshore wind turbines are ranked #1 by Project Drawdown with 147.7 GtCO₂ reduction potential."}, {"question": "How much food is wasted globally?", "options": ["10%", "25%", "33%", "50%"], "correct": 2, "explanation": "Approximately one-third of all food produced globally is lost or wasted."}, {"question": "What is 'drawdown'?", "options": ["Drawing carbon underground", "The point when CO₂ levels stop rising and begin to decline", "Removing CO₂ from the ocean", "A type of carbon credit"], "correct": 1, "explanation": "Drawdown is the future point in time when levels of greenhouse gases in the atmosphere stop climbing and start to steadily decline."}], "completionText": "You've explored 100+ solutions that can reverse global warming. The science is clear, the technology exists, and the economics increasingly favor action."}, {"id": "connect", "type": "text", "title": "Solutions Exist. Personal Action Completes the Picture.", "body": "You've explored <strong>100+ solutions</strong> that can reverse global warming. The science is clear, the technology exists, and the economics increasingly favor action.<br><br>But systemic change starts with <strong>personal understanding</strong> — knowing your own carbon footprint and where you can make the biggest difference.<br><br><strong>How big is YOUR footprint?</strong>", "callouts": [{"label": "Average global footprint", "value": "4.7 tons CO₂/person/year"}, {"label": "Target for 1.5°C", "value": "~2 tons CO₂/person/year by 2030"}, {"label": "US average", "value": "~16 tons CO₂/person/year"}], "actions": [{"id": "next_module", "label": "Calculate Your Footprint →", "type": "next", "style": "primary"}]}]};

window.__EMBEDDED_MODULES__['07-carbon-footprint'] = {"id": "07-carbon-footprint", "title": "Your Carbon Footprint", "description": "Calculate your personal carbon footprint across energy, transport, food, and consumption — then discover exactly where to cut.", "estimated_minutes": 7, "difficulty": "intermediate", "prerequisites": ["01-carbon-atom", "03-carbon-budget", "06-drawdown-solutions"], "next_module": "08-climate-justice", "stages": [{"id": "hook", "type": "text", "title": "Your Lifestyle Has a Carbon Price Tag", "body": "Every choice you make — what you eat, how you travel, what you buy — has a carbon cost. The average American generates <strong>~16 tons of CO₂ per year</strong>. The global target to stay below 1.5°C? <strong>~2 tons per person by 2030</strong>.<br><br>That's an <strong>87% reduction</strong> needed. Scary? Or empowering — because once you know where your emissions come from, you can act precisely.<br><br>Let's calculate your footprint right now.", "callouts": [{"label": "Average American footprint", "value": "~16 tons CO₂/year"}, {"label": "Global average", "value": "~4.7 tons CO₂/year"}, {"label": "Target for 1.5°C", "value": "~2 tons CO₂/year by 2030"}], "gaia": "You can't manage what you don't measure. Let's measure. No judgment — just data. The goal isn't perfection. It's awareness.", "actions": [{"id": "calculate", "label": "Calculate My Footprint →", "type": "next", "style": "primary"}]}, {"id": "slider_inputs", "type": "slider", "title": "Your Carbon Inputs", "description": "Adjust your lifestyle factors to calculate your personal carbon footprint. Be honest — this is for you.", "sliders": [{"label": "Monthly electricity bill ($)", "min": 0, "max": 500, "step": 10, "default": 120, "unit": "$/month"}, {"label": "Car commute (miles/day round trip)", "min": 0, "max": 150, "step": 5, "default": 30, "unit": "miles/day"}, {"label": "Flights per year (long-haul)", "min": 0, "max": 20, "step": 1, "default": 2, "unit": "flights/yr"}, {"label": "Meat-based meals per week", "min": 0, "max": 21, "step": 1, "default": 10, "unit": "meals/wk"}], "gaia": "Most people underestimate their footprint by 2-3x. Don't worry about being exact — the point is to see which levers matter most.", "actions": [{"id": "results", "label": "See My Results →", "type": "next", "style": "primary"}]}, {"id": "gauge_results", "type": "gauge", "title": "Your Footprint vs. Targets", "description": "See how your calculated footprint compares to global averages and climate targets.", "min": 0, "max": 30, "unit": "tons CO₂/yr", "value": 12, "thresholds": [[2, "#5bbf72"], ["#ffa726"], [16, "#f5876a"], [30, "#e53935"]], "gaugeContext": "Green = within 1.5°C target. Yellow = needs reduction. Orange = above global average. Red = above US average. Most people land in the yellow or orange zone.", "actions": [{"id": "quiz", "label": "Knowledge Check →", "type": "next", "style": "primary"}]}, {"id": "quiz", "type": "quiz", "title": "Knowledge Check: Your Impact", "questions": [{"question": "What's the carbon footprint of a round-trip transatlantic flight?", "options": ["0.3 tons", "1.6 tons", "4.5 tons", "10 tons"], "correct": 1, "explanation": "A round-trip economy transatlantic flight generates approximately 1.6 tons CO₂ per passenger."}, {"question": "Which food has the highest carbon footprint per kg?", "options": ["Chicken", "Cheese", "Beef", "Rice"], "correct": 2, "explanation": "Beef produces ~27 kg CO₂-eq per kg of food — roughly 10x chicken and 50x vegetables."}, {"question": "What single home change saves the most CO₂?", "options": ["LED bulbs", "Smart thermostat", "Solar panels", "Better insulation"], "correct": 2, "explanation": "Rooftop solar can offset 3-8 tons CO₂/year depending on location and system size."}, {"question": "How much could plant-rich diets reduce food emissions?", "options": ["10%", "25%", "50%", "70%"], "correct": 2, "explanation": "Shifting toward plant-rich diets could reduce food system emissions by up to 50%."}], "completionText": "You now understand your personal carbon footprint and where the biggest opportunities for reduction lie."}, {"id": "connect", "type": "text", "title": "Your Journey Through Climate Knowledge", "body": "You've journeyed from a single carbon atom through the Keeling Curve, carbon budgets, restoration projects, carbon markets, drawdown solutions, and your own footprint.<br><br><strong>What you now know:</strong><br>✓ The science behind atmospheric CO₂ rise<br>✓ Earth's carbon budget and how close we are to exhausting it<br>✓ Real solutions that exist right now<br>✓ How markets can (and can't) help<br>✓ Your personal impact and where to focus<br><br>But there's one more dimension — the human one. Who suffers most from a crisis they did least to cause?", "callouts": [{"label": "Modules completed", "value": "7 / 8"}, {"label": "Next", "value": "Climate Justice & Equity"}], "actions": [{"id": "next_module", "label": "Explore Climate Justice →", "type": "next", "style": "primary"}]}]};

window.__EMBEDDED_MODULES__['08-climate-justice'] = {"id": "08-climate-justice", "title": "Climate Justice & Equity", "description": "Who bears the burden of a warming planet? Explore the intersection of climate change, inequality, and human rights.", "estimated_minutes": 8, "difficulty": "advanced", "prerequisites": ["01-carbon-atom", "02-keeling-curve", "03-carbon-budget", "06-drawdown-solutions"], "next_module": null, "stages": [{"id": "hook", "type": "text", "title": "The Injustice of Climate Change", "body": "The countries most devastated by climate change contributed the least to causing it.<br><br><strong>The math is devastating:</strong><br>• The <strong>richest 10%</strong> of humanity produces <strong>50%</strong> of all emissions<br>• The <strong>poorest 50%</strong> produces just <strong>12%</strong><br>• Small Island Developing States emit <strong>&lt;1%</strong> of global CO₂ — yet face total extinction from sea-level rise<br>• Sub-Saharan Africa contributes <strong>~3%</strong> of emissions but bears <strong>75%</strong> of climate-related deaths<br><br>Climate change isn't just an environmental crisis. It's a <strong>justice crisis</strong>. It amplifies every existing inequality — poverty, gender, race, geography — and threatens to undo decades of human progress.", "callouts": [{"label": "Rich 10% share of emissions", "value": "50% of all CO₂"}, {"label": "Poorest 50% share", "value": "12% of all CO₂"}, {"label": "Climate refugees (projected 2050)", "value": "200+ million people"}], "gaia": "\"The people who have contributed the least to climate change are the ones suffering the most.\" — Mary Robinson, former President of Ireland", "actions": [{"id": "explore", "label": "Hear Their Stories →", "type": "next", "style": "primary"}]}, {"id": "cardstack_vulnerability", "type": "cardstack", "title": "Voices from the Frontlines", "description": "Meet the communities already living through the climate crisis. Click each card to learn their story.", "filters": ["All", "Sea Level", "Drought", "Extreme Heat", "Flooding"], "cards": [{"title": "Tuvalu — Sinking Nation", "subtitle": "Pacific Ocean · 12,000 people", "icon": "🏝️", "badge": "Existential threat", "category": "Sea Level", "detail": "Tuvalu's highest point is just 4.6 meters above sea level. Rising seas threaten to make the nation uninhabitable within decades. In 2023, Tuvalu signed a landmark deal with Australia offering climate migration pathways. They're also creating a digital twin of their nation — preserving their culture in the cloud.", "stats": ["4.6m max elevation", "1.2°C above pre-industrial", "~50% GDP at risk by 2060"]}, {"title": "Sahel Region — Desertification", "subtitle": "Sub-Saharan Africa · 100M+ people", "icon": "🏜️", "badge": "Food crisis", "category": "Drought", "detail": "The Sahel is warming 1.5x faster than the global average. Lake Chad has shrunk by 90% since the 1960s, displacing millions and fueling conflict. The Great Green Wall initiative aims to restore 100 million hectares of degraded land.", "stats": ["90% Lake Chad shrinkage", "100M+ affected", "1.5x global avg warming rate"]}, {"title": "South Asia — Extreme Heat", "subtitle": "India & Pakistan · 1.8 billion people", "icon": "🌡️", "badge": "Deadly heatwaves", "category": "Extreme Heat", "detail": "2025 saw wet-bulb temperatures exceeding human survivability limits in parts of South Asia. Outdoor laborers, farmers, and the urban poor are most exposed. Air conditioning is a luxury many can't afford — and it creates a feedback loop of more emissions.", "stats": ["51°C recorded (2025)", "600M+ exposed annually", "Wet-bulb limits breached"]}, {"title": "Bangladesh — Flooding", "subtitle": "Ganges Delta · 170 million people", "icon": "🌊", "badge": "Climate displacement", "category": "Flooding", "detail": "One-third of Bangladesh sits less than 5 meters above sea level. By 2050, an estimated 13 million people could be displaced by rising waters and saltwater intrusion. Bangladesh contributes less than 0.5% of global emissions.", "stats": ["170M population at risk", "13M projected climate migrants", "1/3 country below 5m elevation"]}, {"title": "Amazon Indigenous Communities", "subtitle": "Brazil, Peru, Colombia · 1M+ indigenous people", "icon": "🪶", "badge": "Cultural extinction", "category": "Flooding", "detail": "Indigenous peoples protect 80% of world biodiversity. Deforestation, fires, and mining threaten their lands, knowledge systems, and ways of life that span millennia. When the forest falls, so does millennia of wisdom.", "stats": ["80% of biodiversity on indigenous land", "1M+ people affected", "17% forest already lost"]}, {"title": "Arctic Indigenous Peoples", "subtitle": "Alaska, Canada, Siberia · 400,000 people", "icon": "❄️", "badge": "Melting homeland", "category": "Sea Level", "detail": "Arctic warming is 3-4x the global average. Permafrost thaw destroys infrastructure, sea ice loss threatens traditional hunting, and coastal erosion forces community relocations. 31 Alaskan villages are currently relocating.", "stats": ["3-4x global avg warming", "1.5M km² sea ice lost/decade", "31 villages relocating"]}], "gaia": "These aren't statistics. They're people. Families. Cultures. Entire ways of life that took millennia to develop — disappearing in a single generation.", "actions": [{"id": "continue", "label": "What Kind of Justice? →", "type": "next", "style": "primary"}]}, {"id": "branch_justice", "type": "branch", "title": "What Kind of Justice?", "description": "Climate justice means different things to different people. Which dimension matters most to you?", "paths": [{"label": "⏳ Intergenerational Justice", "description": "We're borrowing Earth from future generations. What debt are we leaving?", "icon": "⏳"}, {"label": "💰 Climate Reparations", "description": "Should wealthy, high-emitting nations pay for damages in vulnerable countries?", "icon": "💰"}, {"label": "⚡ Energy Justice", "description": "1.2 billion people lack electricity. Can we decarbonize while lifting people out of poverty?", "icon": "⚡"}, {"label": "✊ Environmental Racism", "description": "Pollution and climate impacts disproportionately affect communities of color worldwide.", "icon": "✊"}]}, {"id": "pledge_gap", "type": "discover", "title": "The Pledge vs. Reality Gap", "body": "In 2015, nearly every nation signed the <strong>Paris Agreement</strong>, pledging to limit warming to 1.5-2°C. But pledges are not policies, and policies are not action.<br><br><strong>Current reality:</strong><br>• National pledges put us on track for <strong>~2.5-2.8°C</strong> of warming — far above safe limits<br>• The <strong>emissions gap</strong> between pledges and 1.5°C targets: <strong>~22 GtCO₂/year</strong><br>• Adaptation finance for developing countries: <strong>~$21B delivered</strong> vs. <strong>$387B needed</strong><br><br>The <strong>Loss and Damage Fund</strong>, established at COP27 (2022) and operationalized at COP28 (2023), was a breakthrough — but contributions total only <strong>~$700M</strong> against estimated needs of <strong>$400B/year by 2030</strong>.<br><br>Justice isn't charity. It's about <strong>acknowledging who caused the problem</strong> and <strong>who has the resources to fix it</strong>.", "callouts": [{"label": "Pledged warming (current NDCs)", "value": "~2.7°C by 2100"}, {"label": "Paris target", "value": "1.5°C"}, {"label": "Emissions gap", "value": "~22 GtCO₂/year by 2030"}, {"label": "Loss & Damage Fund", "value": "~$700M (need: $400B/yr)"}], "gaia": "The gap between what we promise and what we do is the gap between 1.5°C and 3°C. That gap is measured in millions of lives.", "actions": [{"id": "quiz", "label": "Final Challenge →", "type": "next", "style": "primary"}]}, {"id": "quiz", "type": "quiz", "title": "Climate Justice Literacy", "questions": [{"question": "Which group produces 50% of global emissions?", "options": ["The poorest 50%", "The richest 10%", "China alone", "The US military"], "correct": 1, "explanation": "The richest 10% of humanity produces approximately 50% of all consumption-based CO₂ emissions (Oxfam/IPCC)."}, {"question": "What is a 'Loss and Damage' fund?", "options": ["A fund for future space colonization", "Compensation for climate damages in vulnerable nations", "Insurance for fossil fuel companies", "A savings account for future generations"], "correct": 1, "explanation": "Loss and Damage refers to the financial mechanism compensating developing nations for climate impacts they did not cause."}, {"question": "How many climate refugees are projected by 2050?", "options": ["10 million", "100 million", "200+ million", "1 billion"], "correct": 2, "explanation": "The World Bank estimates 216 million people could be internally displaced by climate impacts by 2050."}, {"question": "Arctic regions are warming how fast compared to the global average?", "options": ["Same rate", "2x faster", "3-4x faster", "10x faster"], "correct": 2, "explanation": "Arctic amplification causes warming 3-4 times faster than the global average."}], "completionText": "You now understand climate change at every level — the science, the economics, the solutions, and the human cost."}, {"id": "completion", "type": "text", "title": "Your Journey is Complete", "body": "You now understand climate change at every level:<br><br>🔬 <strong>The Science</strong> — Carbon atoms, the Keeling Curve, Earth's budget<br>💰 <strong>The Economics</strong> — Carbon markets, drawdown solutions, the cost of inaction<br>🌍 <strong>The Justice</strong> — Who suffers, who's responsible, and what fairness demands<br><br>This is the foundation for <strong>COP31 in Antalya</strong> and everything that follows. Knowledge without action is incomplete — but action without knowledge is dangerous.<br><br><strong>Earth doesn't need saving. It needs us to stop breaking it.</strong>", "callouts": [{"label": "Modules completed", "value": "8 / 8"}, {"label": "COP31 Antalya", "value": "November 2026"}, {"label": "Your total XP", "value": "Check the counter above ↑"}], "gaia": "You've completed the journey. But this isn't the end — it's the beginning. The question now is: what will you do with what you know?", "actions": [{"id": "restart", "label": "← Back to All Modules", "type": "complete", "style": "primary"}]}]};

